13	// Mux is a simple HTTP route multiplexer that parses a request path,
14	// records any URL params, and executes an end handler. It implements
15	// the http.Handler interface and is friendly with the standard library.
16	//
17	// Mux is designed to be fast, minimal and offer a powerful API for building
18	// modular and composable HTTP services with a large set of handlers. It's
19	// particularly useful for writing large REST API services that break a handler
20	// into many smaller parts composed of middlewares and end handlers.
21	type Mux struct {
22		// The computed mux handler made of the chained middleware stack and
23		// the tree router
24		handler http.Handler
25	
26		// The radix trie router
27		tree *node
28	
29		// Custom method not allowed handler
30		methodNotAllowedHandler http.HandlerFunc
31	
32		// A reference to the parent mux used by subrouters when mounting
33		// to a parent mux
34		parent *Mux
35	
36		// Routing context pool
37		pool *sync.Pool
38	
39		// Custom route not found handler
40		notFoundHandler http.HandlerFunc
41	
42		// The middleware stack
43		middlewares []func(http.Handler) http.Handler
44	
45		// Controls the behaviour of middleware chain generation when a mux
46		// is registered as an inline group inside another mux.
47		inline bool
48	}
49	
50	// NewMux returns a newly initialized Mux object that implements the Router
51	// interface.
52	func NewMux() *Mux {
53		mux := &Mux{tree: &node{}, pool: &sync.Pool{}}
54		mux.pool.New = func() interface{} {
55			return NewRouteContext()
56		}
57		return mux
58	}
59	
60	// ServeHTTP is the single method of the http.Handler interface that makes
61	// Mux interoperable with the standard library. It uses a sync.Pool to get and
62	// reuse routing contexts for each request.
63	func (mx *Mux) ServeHTTP(w http.ResponseWriter, r *http.Request) {
64		// Ensure the mux has some routes defined on the mux
65		if mx.handler == nil {
66			mx.NotFoundHandler().ServeHTTP(w, r)
67			return
68		}
69	
70		// Check if a routing context already exists from a parent router.
71		rctx, _ := r.Context().Value(RouteCtxKey).(*Context)
72		if rctx != nil {
73			mx.handler.ServeHTTP(w, r)
74			return
75		}
76	
77		// Fetch a RouteContext object from the sync pool, and call the computed
78		// mx.handler that is comprised of mx.middlewares + mx.routeHTTP.
79		// Once the request is finished, reset the routing context and put it back
80		// into the pool for reuse from another request.
81		rctx = mx.pool.Get().(*Context)
82		rctx.Reset()
83		rctx.Routes = mx
84		rctx.parentCtx = r.Context()
85	
86		// NOTE: r.WithContext() causes 2 allocations and context.WithValue() causes 1 allocation
87		r = r.WithContext(context.WithValue(r.Context(), RouteCtxKey, rctx))
88	
89		// Serve the request and once its done, put the request context back in the sync pool
90		mx.handler.ServeHTTP(w, r)
91		mx.pool.Put(rctx)
92	}
93	
94	// Use appends a middleware handler to the Mux middleware stack.
95	//
96	// The middleware stack for any Mux will execute before searching for a matching
97	// route to a specific handler, which provides opportunity to respond early,
98	// change the course of the request execution, or set request-scoped values for
99	// the next http.Handler.
100	func (mx *Mux) Use(middlewares ...func(http.Handler) http.Handler) {
101		if mx.handler != nil {
102			panic("chi: all middlewares must be defined before routes on a mux")
103		}
104		mx.middlewares = append(mx.middlewares, middlewares...)
105	}
106	
107	// Handle adds the route `pattern` that matches any http method to
108	// execute the `handler` http.Handler.
109	func (mx *Mux) Handle(pattern string, handler http.Handler) {
110		mx.handle(mALL, pattern, handler)
111	}
112	
113	// HandleFunc adds the route `pattern` that matches any http method to
114	// execute the `handlerFn` http.HandlerFunc.
115	func (mx *Mux) HandleFunc(pattern string, handlerFn http.HandlerFunc) {
116		mx.handle(mALL, pattern, handlerFn)
117	}
118	
119	// Method adds the route `pattern` that matches `method` http method to
120	// execute the `handler` http.Handler.
121	func (mx *Mux) Method(method, pattern string, handler http.Handler) {
122		m, ok := methodMap[strings.ToUpper(method)]
123		if !ok {
124			panic(fmt.Sprintf("chi: '%s' http method is not supported.", method))
125		}
126		mx.handle(m, pattern, handler)
127	}
128	
129	// MethodFunc adds the route `pattern` that matches `method` http method to
130	// execute the `handlerFn` http.HandlerFunc.
131	func (mx *Mux) MethodFunc(method, pattern string, handlerFn http.HandlerFunc) {
132		mx.Method(method, pattern, handlerFn)
133	}
134	
135	// Connect adds the route `pattern` that matches a CONNECT http method to
136	// execute the `handlerFn` http.HandlerFunc.
137	func (mx *Mux) Connect(pattern string, handlerFn http.HandlerFunc) {
138		mx.handle(mCONNECT, pattern, handlerFn)
139	}
140	
141	// Delete adds the route `pattern` that matches a DELETE http method to
142	// execute the `handlerFn` http.HandlerFunc.
143	func (mx *Mux) Delete(pattern string, handlerFn http.HandlerFunc) {
144		mx.handle(mDELETE, pattern, handlerFn)
145	}
146	
147	// Get adds the route `pattern` that matches a GET http method to
148	// execute the `handlerFn` http.HandlerFunc.
149	func (mx *Mux) Get(pattern string, handlerFn http.HandlerFunc) {
150		mx.handle(mGET, pattern, handlerFn)
151	}
152	
153	// Head adds the route `pattern` that matches a HEAD http method to
154	// execute the `handlerFn` http.HandlerFunc.
155	func (mx *Mux) Head(pattern string, handlerFn http.HandlerFunc) {
156		mx.handle(mHEAD, pattern, handlerFn)
157	}
158	
159	// Options adds the route `pattern` that matches an OPTIONS http method to
160	// execute the `handlerFn` http.HandlerFunc.
161	func (mx *Mux) Options(pattern string, handlerFn http.HandlerFunc) {
162		mx.handle(mOPTIONS, pattern, handlerFn)
163	}
164	
165	// Patch adds the route `pattern` that matches a PATCH http method to
166	// execute the `handlerFn` http.HandlerFunc.
167	func (mx *Mux) Patch(pattern string, handlerFn http.HandlerFunc) {
168		mx.handle(mPATCH, pattern, handlerFn)
169	}
170	
171	// Post adds the route `pattern` that matches a POST http method to
172	// execute the `handlerFn` http.HandlerFunc.
173	func (mx *Mux) Post(pattern string, handlerFn http.HandlerFunc) {
174		mx.handle(mPOST, pattern, handlerFn)
175	}
176	
177	// Put adds the route `pattern` that matches a PUT http method to
178	// execute the `handlerFn` http.HandlerFunc.
179	func (mx *Mux) Put(pattern string, handlerFn http.HandlerFunc) {
180		mx.handle(mPUT, pattern, handlerFn)
181	}
182	
183	// Trace adds the route `pattern` that matches a TRACE http method to
184	// execute the `handlerFn` http.HandlerFunc.
185	func (mx *Mux) Trace(pattern string, handlerFn http.HandlerFunc) {
186		mx.handle(mTRACE, pattern, handlerFn)
187	}
