776	type nodes []*node
777	
778	// Sort the list of nodes by label
779	func (ns nodes) Sort()              { sort.Sort(ns); ns.tailSort() }
780	func (ns nodes) Len() int           { return len(ns) }
781	func (ns nodes) Swap(i, j int)      { ns[i], ns[j] = ns[j], ns[i] }
782	func (ns nodes) Less(i, j int) bool { return ns[i].label < ns[j].label }
783	
784	// tailSort pushes nodes with '/' as the tail to the end of the list for param nodes.
785	// The list order determines the traversal order.
786	func (ns nodes) tailSort() {
787		for i := len(ns) - 1; i >= 0; i-- {
788			if ns[i].typ > ntStatic && ns[i].tail == '/' {
789				ns.Swap(i, len(ns)-1)
790				return
791			}
792		}
793	}
794	
795	func (ns nodes) findEdge(label byte) *node {
796		num := len(ns)
797		idx := 0
798		i, j := 0, num-1
799		for i <= j {
800			idx = i + (j-i)/2
801			if label > ns[idx].label {
802				i = idx + 1
803			} else if label < ns[idx].label {
804				j = idx - 1
805			} else {
806				i = num // breaks cond
807			}
808		}
809		if ns[idx].label != label {
810			return nil
811		}
812		return ns[idx]
813	}
