import (
	"net/http"
	"net/http/httptest"
	"testing"
)

func TestCORSSmoke(t *testing.T) {
	r := NewRouter()
	r.EnableCORS()
	r.Get("/api/users", func(w http.ResponseWriter, r *http.Request) { w.Write([]byte("ok")) })
	r.Post("/api/users", func(w http.ResponseWriter, r *http.Request) { w.Write([]byte("ok")) })

	// normal GET
	{
		req := httptest.NewRequest("GET", "/api/users", nil)
		w := httptest.NewRecorder()
		r.ServeHTTP(w, req)
		if got := w.Header().Get("Access-Control-Allow-Origin"); got != "*" {
			t.Fatalf("expected wildcard origin, got %q", got)
		}
	}

	// preflight OPTIONS
	{
		req := httptest.NewRequest("OPTIONS", "/api/users", nil)
		w := httptest.NewRecorder()
		r.ServeHTTP(w, req)
		if w.Code != 204 {
			t.Fatalf("expected 204, got %d", w.Code)
		}
		methods := w.Header().Get("Access-Control-Allow-Methods")
		if !contains(methods, "GET") || !contains(methods, "POST") {
			t.Fatalf("expected GET and POST in methods, got %q", methods)
		}
		if w.Header().Get("Access-Control-Allow-Headers") == "" {
			t.Fatal("expected non-empty allow-headers")
		}
		if w.Header().Get("Access-Control-Max-Age") == "" {
			t.Fatal("expected non-empty max-age")
		}
	}

	// method not allowed
	{
		req := httptest.NewRequest("PUT", "/api/users", nil)
		w := httptest.NewRecorder()
		r.ServeHTTP(w, req)
		if w.Code != 405 {
			t.Fatalf("expected 405, got %d", w.Code)
		}
		allow := w.Header().Get("Allow")
		if !contains(allow, "GET") {
			t.Fatalf("expected GET in Allow header, got %q", allow)
		}
	}
}

func contains(s, substr string) bool {
	for i := 0; i+len(substr) <= len(s); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}
"}

