func TestDebugWithCORS(t *testing.T) {
	r := NewRouter()
	api := r.WithCORS()
	api.Get("/widgets", func(w http.ResponseWriter, r *http.Request) { w.Write([]byte("ok")) })

	req := httptest.NewRequest("GET", "/widgets", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)
	if got := w.Header().Get("Access-Control-Allow-Origin"); got != "*" {
		t.Fatalf("expected wildcard origin, got %q", got)
	}
}

func TestDebugEnableCORSWithOptions(t *testing.T) {
	r := NewRouter()
	r.EnableCORSWithOptions(CORSOptions{
		AllowOrigin:      "https://example.com",
		AllowCredentials: true,
		AllowHeaders:     []string{"X-Custom"},
		MaxAge:           60,
	})
	r.Get("/x", func(w http.ResponseWriter, r *http.Request) {})

	req := httptest.NewRequest("GET", "/x", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)
	if got := w.Header().Get("Access-Control-Allow-Origin"); got != "https://example.com" {
		t.Fatalf("got %q", got)
	}
	if got := w.Header().Get("Access-Control-Allow-Credentials"); got != "true" {
		t.Fatalf("got %q", got)
	}

	req2 := httptest.NewRequest("OPTIONS", "/x", nil)
	w2 := httptest.NewRecorder()
	r.ServeHTTP(w2, req2)
	if w2.Code != 204 {
		t.Fatalf("status %d", w2.Code)
	}
	if got := w2.Header().Get("Access-Control-Allow-Methods"); got != "GET" {
		t.Fatalf("got %q", got)
	}
	if got := w2.Header().Get("Access-Control-Allow-Headers"); got != "X-Custom" {
		t.Fatalf("got %q", got)
	}
	if got := w2.Header().Get("Access-Control-Max-Age"); got != "60" {
		t.Fatalf("got %q", got)
	}
}
EOF
export PATH=$PATH:/usr/local/go/bin && go test ./ -run 'TestDebugWithCORS|TestDebugEnableCORSWithOptions' -v -count=1 2>&1"}
